/**
 * 1) Recursively collect every string in the Slack payload (including nested blocks/attachments).
 * 2) Join them into one line, strip Slack’s <url|text> formatting.
 * 3) Extract handle, platform, link, and other text fields from the message.
 */

function collectStrings(obj, out = []) {
  if (typeof obj === 'string') {
    out.push(obj);
  } else if (Array.isArray(obj)) {
    obj.forEach(el => collectStrings(el, out));
  } else if (obj && typeof obj === 'object') {
    Object.values(obj).forEach(v => collectStrings(v, out));
  }
  return out;
}

// 1. Grab the raw message text if present (sometimes Slack puts it under event.text)
const plainText = $json.event && $json.event.text
                  ? $json.event.text
                  : ($json.text || '');

// 2. Flatten every string (from blocks, attachments, etc.) into one line
const allStrings = collectStrings($json.event || $json);
let flat = allStrings.join(' ').replace(/\s+/g, ' ');

// 3. Strip Slack link formatting: <https://…|someText> → someText
flat = flat.replace(/<[^|>]+\|([^>]+)>/g, '$1');

// 4. Extract the handle and platform
const handleMatch   = flat.match(/\bby\s+([^\s]+)/i);
const handle        = handleMatch ? handleMatch[1].replace(/^\*+|\*+$/g, '') : '';

const platformMatch = flat.match(/\bon\s+(instagram|tiktok)\b/i);
let platform        = platformMatch ? platformMatch[1].toUpperCase() : '';

// 5. Extract "Link to post" (URLs typically)
const linkMatch = flat.match(/<https:\/\/[^\s]+>/g);  // This captures any URLs starting with https://
const linkToPost = linkMatch ? linkMatch[0].replace(/[<>]/g, '') : '';  // Remove the angle brackets

// 6. Extract followers count (if present)
const followersMatch = flat.match(/\*Followers\*: (\d+)/);
const followers = followersMatch ? followersMatch[1] : '';

// 7. Extract media type (if present)
const mediaTypeMatch = flat.match(/Media Type: (\w+)/);
const mediaType = mediaTypeMatch ? mediaTypeMatch[1] : '';

// 8. Extract post date (if present)
const postDateMatch = flat.match(/\*Posted at\*: ([\d\-]+)/);
const postDate = postDateMatch ? postDateMatch[1] : '';

// 9. Extract any other relevant information (e.g., "Powered by" URL, etc.)
const poweredByMatch = flat.match(/Powered by:\s*<([^>]+)>/);
const poweredBy = poweredByMatch ? poweredByMatch[1] : '';

// 10. Return the structured result with all the extracted fields
return [{
  handle,
  platform,
  linkToPost,
  followers,
  mediaType,
  postDate,
  poweredBy,
  rawText: flat // Including all the raw text for reference
}];
